+    #[test]
+    fn nanpercentile_matches_numpy_across_q_axis_method_keepdims_and_all_nan() {
+        with_python(|py| {
+            if !numpy_available(py) {
+                return Ok(());
+            }
+
+            let module = PyModule::new(py, "fnp_python_test")?;
+            fnp_python(&module)?;
+            let nanpercentile_fn = module.getattr("nanpercentile")?;
+            let numpy = py.import("numpy")?;
+            let numpy_nanpercentile = numpy.getattr("nanpercentile")?;
+            let isclose = numpy.getattr("isclose")?;
+            let allclose = numpy.getattr("allclose")?;
+            let isnan = numpy.getattr("isnan")?;
+            let warnings = py.import("warnings")?;
+
+            // Scalar q on 1-D with NaNs ignored.
+            let one_d =
+                numpy
+                    .getattr("array")?
+                    .call1((vec![3.0_f64, f64::NAN, 1.0, 5.0, 9.0, 2.0],))?;
+            let ours = nanpercentile_fn.call1((one_d.clone(), 50.0_f64))?;
+            let theirs = numpy_nanpercentile.call1((one_d.clone(), 50.0_f64))?;
+            let ok: bool = isclose
+                .call(
+                    (&ours, &theirs),
+                    Some(&{
+                        let kw = PyDict::new(py);
+                        kw.set_item("equal_nan", true)?;
+                        kw
+                    }),
+                )?
+                .extract()?;
+            assert!(ok, "nanpercentile q=50 1-D mismatch");
+
+            // Vector q.
+            let qs = numpy
+                .getattr("array")?
+                .call1((vec![25.0_f64, 50.0, 75.0],))?;
+            let ours_qs = nanpercentile_fn.call1((one_d.clone(), qs.clone()))?;
+            let theirs_qs = numpy_nanpercentile.call1((one_d.clone(), qs.clone()))?;
+            let ok_qs: bool = allclose
+                .call(
+                    (&ours_qs, &theirs_qs),
+                    Some(&{
+                        let kw = PyDict::new(py);
+                        kw.set_item("equal_nan", true)?;
+                        kw
+                    }),
+                )?
+                .extract()?;
+            assert!(ok_qs, "nanpercentile vector q mismatch");
+
+            // 2-D axis reductions with mixed NaNs.
+            let two_d = numpy.getattr("array")?.call1((vec![
+                vec![1.0_f64, f64::NAN, 3.0, 7.0],
+                vec![4.0, 2.0, f64::NAN, 8.0],
+                vec![7.0, 8.0, 9.0, f64::NAN],
+            ],))?;
+            for axis in [0_i64, 1] {
+                let ours_ax = nanpercentile_fn.call(
+                    (two_d.clone(), 50.0_f64),
+                    Some(&{
+                        let kw = PyDict::new(py);
+                        kw.set_item("axis", axis)?;
+                        kw
+                    }),
+                )?;
+                let theirs_ax = numpy_nanpercentile.call(
+                    (two_d.clone(), 50.0_f64),
+                    Some(&{
+                        let kw = PyDict::new(py);
+                        kw.set_item("axis", axis)?;
+                        kw
+                    }),
+                )?;
+                assert_array_matches_numpy(&ours_ax, &theirs_ax)?;
+            }
+
+            // keepdims=True shape parity.
+            let ours_kd = nanpercentile_fn.call(
+                (two_d.clone(), 50.0_f64),
+                Some(&{
+                    let kw = PyDict::new(py);
+                    kw.set_item("axis", 1_i64)?;
+                    kw.set_item("keepdims", true)?;
+                    kw
+                }),
+            )?;
+            let theirs_kd = numpy_nanpercentile.call(
+                (two_d.clone(), 50.0_f64),
+                Some(&{
+                    let kw = PyDict::new(py);
+                    kw.set_item("axis", 1_i64)?;
+                    kw.set_item("keepdims", true)?;
+                    kw
+                }),
+            )?;
+            assert_array_matches_numpy(&ours_kd, &theirs_kd)?;
+
+            // Method variants.
+            for method in ["linear", "lower", "higher"] {
+                let ours_m = nanpercentile_fn.call(
+                    (one_d.clone(), 50.0_f64),
+                    Some(&{
+                        let kw = PyDict::new(py);
+                        kw.set_item("method", method)?;
+                        kw
+                    }),
+                )?;
+                let theirs_m = numpy_nanpercentile.call(
+                    (one_d.clone(), 50.0_f64),
+                    Some(&{
+                        let kw = PyDict::new(py);
+                        kw.set_item("method", method)?;
+                        kw
+                    }),
+                )?;
+                let ok_m: bool = isclose
+                    .call(
+                        (&ours_m, &theirs_m),
+                        Some(&{
+                            let kw = PyDict::new(py);
+                            kw.set_item("equal_nan", true)?;
+                            kw
+                        }),
+                    )?
+                    .extract()?;
+                assert!(ok_m, "nanpercentile method={} mismatch", method);
+            }
+
+            // Integer input parity with overwrite_input forwarded.
+            let ints = numpy
+                .getattr("array")?
+                .call1((vec![1_i64, 2, 3, 4, 5, 6, 7, 8],))?;
+            let ours_int = nanpercentile_fn.call(
+                (ints.clone(), 50.0_f64),
+                Some(&{
+                    let kw = PyDict::new(py);
+                    kw.set_item("overwrite_input", false)?;
+                    kw
+                }),
+            )?;
+            let theirs_int = numpy_nanpercentile.call(
+                (ints.clone(), 50.0_f64),
+                Some(&{
+                    let kw = PyDict::new(py);
+                    kw.set_item("overwrite_input", false)?;
+                    kw
+                }),
+            )?;
+            let ok_int: bool = isclose
+                .call(
+                    (&ours_int, &theirs_int),
+                    Some(&{
+                        let kw = PyDict::new(py);
+                        kw.set_item("equal_nan", true)?;
+                        kw
+                    }),
+                )?
+                .extract()?;
+            assert!(ok_int, "nanpercentile integer input mismatch");
+            assert_eq!(
+                ours_int.getattr("dtype")?.str()?.to_string(),
+                theirs_int.getattr("dtype")?.str()?.to_string(),
+                "nanpercentile integer input dtype must match numpy",
+            );
+
+            // Fully-NaN lane returns NaN with warnings silenced.
+            let all_nan = numpy.getattr("array")?.call1((vec![f64::NAN, f64::NAN],))?;
+            let catch_warnings = warnings.getattr("catch_warnings")?;
+            let suppressed_ours = {
+                let ctx = catch_warnings.call0()?;
+                ctx.call_method0("__enter__")?;
+                warnings.call_method1("simplefilter", ("ignore",))?;
+                let result = nanpercentile_fn.call1((all_nan.clone(), 50.0_f64))?;
+                ctx.call_method1("__exit__", (py.None(), py.None(), py.None()))?;
+                result
+            };
+            let suppressed_theirs = {
+                let ctx = catch_warnings.call0()?;
+                ctx.call_method0("__enter__")?;
+                warnings.call_method1("simplefilter", ("ignore",))?;
+                let result = numpy_nanpercentile.call1((all_nan.clone(), 50.0_f64))?;
+                ctx.call_method1("__exit__", (py.None(), py.None(), py.None()))?;
+                result
+            };
+            let ours_is_nan: bool = isnan.call1((&suppressed_ours,))?.extract()?;
+            let theirs_is_nan: bool = isnan.call1((&suppressed_theirs,))?.extract()?;
+            assert!(
+                ours_is_nan && theirs_is_nan,
+                "fully-NaN nanpercentile must be NaN",
+            );
+
+            Ok(())
+        });
+    }
